import{_ as a,o as e,c as l,a2 as o}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"凯文·克莱顿","description":"","frontmatter":{"title":"凯文·克莱顿"},"headers":[],"relativePath":"04_people/凯文·克莱顿.md","filePath":"04_people/凯文·克莱顿.md"}'),r={name:"04_people/凯文·克莱顿.md"};function h(i,t,n,d,s,u){return e(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="凯文·克莱顿-kevin-clayton" tabindex="-1">凯文·克莱顿（Kevin Clayton） <a class="header-anchor" href="#凯文·克莱顿-kevin-clayton" aria-label="Permalink to &quot;凯文·克莱顿（Kevin Clayton）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>Kevin Clayton（凯文·克莱顿）</td></tr><tr><td><strong>职位</strong></td><td>Clayton Homes CEO</td></tr><tr><td><strong>关联公司</strong></td><td>Clayton Homes（克莱顿家园）</td></tr><tr><td><strong>首次提及</strong></td><td>2003年</td></tr></tbody></table><h2 id="与巴菲特的故事" tabindex="-1">与巴菲特的故事 <a class="header-anchor" href="#与巴菲特的故事" aria-label="Permalink to &quot;与巴菲特的故事&quot;">​</a></h2><p>凯文·克莱顿是克莱顿家园创始人吉姆·克莱顿的儿子，2003年伯克希尔收购克莱顿家园后出任CEO，在行业低迷中创造了卓越的业绩。</p><h3 id="收购起源" tabindex="-1">收购起源 <a class="header-anchor" href="#收购起源" aria-label="Permalink to &quot;收购起源&quot;">​</a></h3><p>收购克莱顿家园的起因颇为传奇。田纳西大学的学生送给巴菲特一本吉姆·克莱顿的自传，巴菲特读后对克莱顿家园的卓越表现印象深刻，随后在教授建议下致电凯文·克莱顿：</p><blockquote><p>&quot;在与凯文交谈时，我清楚地意识到他既有能力又是一个直率的人。不久之后，我仅根据吉姆的书、我对凯文的评估、克莱顿的公开财务报表以及我从Oakwood经验中学到的东西，对这项业务提出了报价。&quot;（2003年股东信）</p></blockquote><h3 id="行业逆境中的明星" tabindex="-1">行业逆境中的明星 <a class="header-anchor" href="#行业逆境中的明星" aria-label="Permalink to &quot;行业逆境中的明星&quot;">​</a></h3><p>收购后，预制房行业持续低迷，但凯文的表现令巴菲特赞叹：</p><blockquote><p>&quot;我们金融板块的明星是凯文·克莱顿卓越运营的Clayton Homes。他的辉煌记录并非得益于水涨船高：自2003年伯克希尔收购Clayton以来，活动房屋行业一直令人失望。行业销售徘徊在40年低点附近……近年来，许多行业参与者遭受了损失，只有Clayton赚到了可观的利润。&quot;（2005年股东信）</p></blockquote><blockquote><p>&quot;Clayton实现了5.13亿美元的税前收益，并向伯克希尔额外支付了8,600万美元……Clayton现在雇用14,787人，而我们收购时为6,661人。&quot;（2006年股东信）</p></blockquote><blockquote><p>&quot;Clayton仍是美国第一大家屋建造商……克莱顿CEO凯文·克莱顿出色地引导公司度过严重的房地产萧条。&quot;（2013年股东信）</p></blockquote><h3 id="金融业务" tabindex="-1">金融业务 <a class="header-anchor" href="#金融业务" aria-label="Permalink to &quot;金融业务&quot;">​</a></h3><p>凯文还领导克莱顿拓展了抵押贷款服务业务，从收购时的54亿美元增长到170亿美元，成为公司利润的重要来源。</p><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2003, 2005, 2006, 2008, 2013</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/Clayton_Homes.html">Clayton Homes</a> - 管理的公司</li><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 母公司</li></ul><hr><p><em>最后更新：2026-04-09</em></p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/2004年/翻译.html">2004年</a></li><li><a href="./../01_letters/2005年/翻译.html">2005年</a></li><li><a href="./../01_letters/2006年/翻译.html">2006年</a></li><li><a href="./../01_letters/2007年/翻译.html">2007年</a></li><li><a href="./../01_letters/2009年/翻译.html">2009年</a></li><li><a href="./../01_letters/2012年/翻译.html">2012年</a></li><li><a href="./../01_letters/2017年/翻译.html">2017年</a></li><li><a href="./../01_letters/2019年/翻译.html">2019年</a></li><li><a href="./../01_letters/2020年/翻译.html">2020年</a></li></ul>',23)])])}const p=a(r,[["render",h]]);export{c as __pageData,p as default};
